INSERT INTO `articles` VALUES (1,'เธเธญเธเธญเธกเธเธดเธงเน€เธ•เธญเธฃเน 144Hz vs 240Hz: เธเธฃเธฐเธชเธเธเธฒเธฃเธ“เนเธ•เนเธฒเธเธเธฑเธเธเธฃเธดเธเธซเธฃเธทเธญเนเธเนเธ•เธฑเธงเน€เธฅเธเธ—เธฒเธเธเธฒเธฃเธ•เธฅเธฒเธ”?','เนเธเนเธฅเธเธเธญเธเน€เธเธกเธกเธดเนเธเนเธฅเธฐเธเธฒเธเธ—เธตเนเธ•เนเธญเธเธเธฒเธฃเธเธงเธฒเธกเธฅเธทเนเธเนเธซเธฅเธเธญเธเธ เธฒเธ เธเธญเธ เธฒเธเธ—เธตเนเธกเธตเธญเธฑเธ•เธฃเธฒเธฃเธตเน€เธเธฃเธเธชเธนเธ (High Refresh Rate) เนเธ”เนเธเธฅเธฒเธขเน€เธเนเธเธกเธฒเธ•เธฃเธเธฒเธเนเธซเธกเนเธ—เธตเนเน€เธฃเธฒเธเธธเนเธเน€เธเธขเธเธฑเธเธ”เธต เนเธ”เธขเน€เธเธเธฒเธฐเธเธญ 144Hz เธ—เธตเนเธกเธญเธเธเธฃเธฐเธชเธเธเธฒเธฃเธ“เนเธ—เธตเนเน€เธซเธเธทเธญเธเธงเนเธฒเธเธญ 60Hz เธญเธขเนเธฒเธเน€เธซเนเธเนเธ”เนเธเธฑเธ”<br><br>เนเธ•เนเน€เธกเธทเนเธญเธเนเธฒเธงเน€เธเนเธฒเธชเธนเนเธชเธเธฒเธกเนเธเนเธเธเธฑเธเธ—เธตเนเธ”เธธเน€เธ”เธทเธญเธ”เธเธถเนเธ เธ•เธฑเธงเน€เธฅเธ 240Hz เธเนเน€เธฃเธดเนเธกเน€เธเนเธฒเธกเธฒเธกเธตเธเธ—เธเธฒเธ— เธ—เธณเนเธซเนเน€เธเธดเธ”เธเธณเธ–เธฒเธกเธงเนเธฒ เธเธฒเธฃเธญเธฑเธเน€เธเธฃเธ”เธเธฒเธ 144Hz เนเธ 240Hz เธเธฑเนเธเธเธธเนเธกเธเนเธฒเธเธฃเธดเธเธซเธฃเธทเธญเน€เธเนเธเน€เธเธตเธขเธเธ•เธฑเธงเน€เธฅเธเธ—เธตเนเธเธฑเธเธเธฒเธฃเธ•เธฅเธฒเธ”เนเธเนเน€เธเธทเนเธญเธ”เธถเธเธ”เธนเธ”เนเธ? <br><br>เธเธงเธฒเธกเนเธ•เธเธ•เนเธฒเธเธฃเธฐเธซเธงเนเธฒเธ 144Hz เนเธฅเธฐ 240Hz เธเธฑเนเธ <strong>เธกเธตเธญเธขเธนเนเธเธฃเธดเธ</strong> เนเธ•เนเธชเธณเธซเธฃเธฑเธเธเธนเนเนเธเนเธเธฒเธเธ—เธฑเนเธงเนเธเธซเธฃเธทเธญเนเธกเนเนเธ•เนเธเธฑเธเน€เธฅเนเธเน€เธเธกเธชเนเธงเธเนเธซเธเน เธเธงเธฒเธกเนเธ•เธเธ•เนเธฒเธเธญเธฒเธเธเธฐเนเธกเนเนเธ”เนเธเธฑเธ”เน€เธเธเธเธเธ–เธถเธเธเธฑเนเธเธเธฅเธดเธเนเธฅเธเน€เธ—เนเธฒเธเธฑเธเธเธฒเธฃเน€เธเธฅเธตเนเธขเธเธเธฒเธ 60Hz เนเธ 144Hz เธเธญ 240Hz เธเธฐเธกเธญเธเธเธงเธฒเธกเธฅเธทเนเธเนเธซเธฅเธ—เธตเนเน€เธซเธเธทเธญเธเธงเนเธฒเนเธเธ—เธธเธเน€เธเธฃเธก เธ—เธณเนเธซเนเธ เธฒเธเธ”เธนเธเธกเธเธฑเธ”เนเธฅเธฐเธ•เธญเธเธชเธเธญเธเนเธ”เนเธ—เธฑเธเธ—เนเธงเธเธ—เธตเธกเธฒเธเธเธถเนเธ เธเธถเนเธเน€เธเนเธเธเธฃเธฐเนเธขเธเธเนเธญเธขเนเธฒเธเธกเธฒเธเนเธเน€เธเธกเนเธเนเธเธเธฑเธเธ—เธตเนเธ•เนเธญเธเธญเธฒเธจเธฑเธขเธเธเธดเธเธดเธฃเธดเธขเธฒเธ•เธญเธเธชเธเธญเธเธ—เธตเนเธฃเธงเธ”เน€เธฃเนเธง เน€เธเนเธ เน€เธเธกเนเธเธง FPS เธซเธฃเธทเธญ eSports เธฃเธฐเธ”เธฑเธเธกเธทเธญเธญเธฒเธเธตเธเธ—เธตเนเธ—เธธเธเธกเธดเธฅเธฅเธดเธงเธดเธเธฒเธ—เธตเธกเธตเธเธงเธฒเธกเธซเธกเธฒเธข เธญเธขเนเธฒเธเนเธฃเธเนเธ•เธฒเธก เธเธฒเธฃเธเธฐเธเธฑเธเน€เธเธฅเธทเนเธญเธเธเธญ 240Hz เนเธซเนเน€เธ•เนเธกเธเธฃเธฐเธชเธดเธ—เธเธดเธ เธฒเธ เธเธธเธ“เธเธณเน€เธเนเธเธ•เนเธญเธเธกเธต <strong>เธเธฒเธฃเนเธ”เธเธญเธ—เธตเนเธ—เธฃเธเธเธฅเธฑเธเธกเธฒเธเธเธญ</strong> เน€เธเธทเนเธญเนเธซเนเนเธ”เนเน€เธเธฃเธกเน€เธฃเธ•เธชเธนเธเธ–เธถเธ 240 FPS เธญเธขเนเธฒเธเธชเธกเนเธณเน€เธชเธกเธญเนเธเน€เธเธกเธ—เธตเนเธเธธเธ“เน€เธฅเนเธ เธเธญเธเธเธฒเธเธเธตเน เธ”เธงเธเธ•เธฒเธเธญเธเธกเธเธธเธฉเธขเนเธกเธตเธเธงเธฒเธกเธชเธฒเธกเธฒเธฃเธ–เนเธเธเธฒเธฃเธฃเธฑเธเธฃเธนเนเธ—เธตเนเนเธ•เธเธ•เนเธฒเธเธเธฑเธ เธเธฒเธเธเธเธญเธฒเธเธชเธฑเธกเธเธฑเธชเธ–เธถเธเธเธงเธฒเธกเนเธ•เธเธ•เนเธฒเธเนเธ”เนเนเธเธ—เธฑเธเธ—เธต เนเธเธเธ“เธฐเธ—เธตเนเธเธฒเธเธเธเธญเธฒเธเธ•เนเธญเธเนเธเนเน€เธงเธฅเธฒเธเธฃเธฑเธเธ•เธฑเธงเธซเธฃเธทเธญเธญเธฒเธเนเธกเนเธฃเธนเนเธชเธถเธเธ–เธถเธเธเธงเธฒเธกเธ•เนเธฒเธเธ—เธตเนเธเธฑเธ”เน€เธเธเธเธฑเธ<br><br>เธชเธฃเธธเธเธเธทเธญ เธซเธฒเธเธเธธเธ“เน€เธเนเธเธเธฑเธเน€เธฅเนเธเน€เธเธกเธกเธทเธญเธญเธฒเธเธตเธ เธซเธฃเธทเธญเธ•เนเธญเธเธเธฒเธฃเธเธงเธฒเธกเนเธ”เนเน€เธเธฃเธตเธขเธเธชเธนเธเธชเธธเธ”เนเธเธ—เธธเธเธชเธ–เธฒเธเธเธฒเธฃเธ“เน เนเธฅเธฐเธกเธตเธเธเธเธฃเธฐเธกเธฒเธ“เธชเธณเธซเธฃเธฑเธเธเธฒเธฃเนเธ”เธเธญเนเธฅเธฐเธเธญเธ เธฒเธเธฃเธฐเธ”เธฑเธเธชเธนเธ เธเธญ 240Hz เธเธทเธญเธเธณเธ•เธญเธเธ—เธตเนเนเธกเนเธ—เธณเนเธซเนเธเธดเธ”เธซเธงเธฑเธ เนเธ•เนเธชเธณเธซเธฃเธฑเธเธเธนเนเนเธเนเธเธฒเธเธ—เธฑเนเธงเนเธเธซเธฃเธทเธญเธเธฑเธเน€เธฅเนเธเน€เ